func (c *current) onFieldAccessExpr1(base, rest any) (any, error) {
	result := base.(ast.Expression)
	if rest != nil {
		for _, r := range rest.([]interface{}) {
			switch suffix := r.(type) {
			case string:
				// Field access: .member
				result = &ast.FieldAccess{
					Base:   result,
					Member: suffix,
				}
			case ast.Expression:
				// Tuple index: [index]
				result = &ast.TupleIndex{
					Tuple: result,
					Index: suffix,
				}
			}
		}
	}
	return result, nil
}

