func (c *current) onStringContent1(chars any) (any, error) {
	var sb strings.Builder
	if chars == nil {
		return "", nil
	}
	for _, ch := range chars.([]interface{}) {
		sb.WriteString(ch.(string))
	}
	return sb.String(), nil
}

func (p *parser) callonStringContent1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onStringContent1(stack["chars"])
}

func (c *current) onEscapeSequence1(seq any) (any, error) {
	seqBytes := seq.([]byte)
	if len(seqBytes) > 0 {
		switch seqBytes[0] {
		case '"':
			return "\"", nil
		case '\\':
			return "\\", nil
		case 'n':
			return "\n", nil
		case 't':
			return "\t", nil
		case 'r':
			return "\r", nil
		case 'f':
			return "\f", nil
		}
	}
	return string(seqBytes), nil
}

func (p *parser) callonEscapeSequence1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onEscapeSequence1(stack["seq"])
}

